@WebMvcTest(MobileOrderController.class)@Import({SecurityConfig.class,MobileExceptionHandler.class})@ContextConfiguration(classes={MobileOrderController.class,SecurityConfig.class,MobileExceptionHandler.class})class MobileOrderSecurityTest{@Autowired MockMvc mvc;@MockitoBean MobileOrderService service;@MockitoBean UserDetailsServiceImpl users;@MockitoBean JwtUtils jwt;@MockitoBean CustomerAuthTokenFilter filter;@BeforeEach void setup()throws Exception{doAnswer(i->{((FilterChain)i.getArgument(2)).doFilter((ServletRequest)i.getArgument(0),(ServletResponse)i.getArgument(1));return null;}).when(filter).doFilter(any(),any(),any());when(service.account(any())).thenReturn(7L);OrderSummary summary=new OrderSummary("TSS-1",Instant.parse("2026-01-01T00:00:00Z"),"PENDING_CONFIRMATION","Pending Confirmation","NOT_STARTED",new BigDecimal("185.00"),"BDT",2,1,"Cable",null,0,"Standard",true,false);when(service.list(eq(7L),anyInt(),anyInt(),any(),any(),any(),any(),any(),any())).thenReturn(new OrderPage(List.of(summary),0,10,1,1,true,true));EligibilityResponse cancel=new EligibilityResponse(true,"ELIGIBLE","Can request cancellation",null);ReturnEligibilityResponse ret=new ReturnEligibilityResponse(false,"ORDER_NOT_DELIVERED","Returns are available only after delivery.",7,List.of(),null);OrderDetail detail=new OrderDetail("TSS-1",Instant.parse("2026-01-01T00:00:00Z"),Instant.parse("2026-01-01T00:00:00Z"),"PENDING_CONFIRMATION","Pending Confirmation","NOT_STARTED","UNPOSTED","BDT",new BigDecimal("100.00"),new BigDecimal("5.00"),new BigDecimal("80.00"),BigDecimal.ZERO,new BigDecimal("185.00"),List.of(new OrderItemSnapshot(1L,2L,null,"Cable","SKU",null,null,new BigDecimal("100.00"),1,new BigDecimal("100.00"),new BigDecimal("5.00"),new BigDecimal("5.00"))),new DeliverySnapshot("A","017****00","Dhaka","Standard"),null,List.of(new TimelineEntry("PENDING_CONFIRMATION","Pending Confirmation","Submitted",Instant.parse("2026-01-01T00:00:00Z"),true,true,null)),cancel,ret,true);when(service.detail(7L,"TSS-1")).thenReturn(detail);when(service.timeline(7L,"TSS-1")).thenReturn(detail.timeline());when(service.cancellationEligibility(7L,"TSS-1")).thenReturn(cancel);when(service.returnEligibility(7L,"TSS-1")).thenReturn(ret);when(service.cancel(eq(7L),eq("TSS-1"),any())).thenReturn(new CancellationRequestResponse("TSS-1","REQUESTED","ORDERED_BY_MISTAKE",null,Instant.parse("2026-01-01T00:00:00Z"),"received"));when(service.createReturn(eq(7L),eq("TSS-1"),any())).thenReturn(new ReturnRequestResponse("RETREQ-1","TSS-1","REQUESTED","REFUND_REQUESTED",Instant.parse("2026-01-01T00:00:00Z"),List.of(),"received"));when(service.document(7L,"TSS-1")).thenReturn(new OrderDocumentResponse("TSS-1","TSS-1-order-summary.html","text/html","Order Summary","<p>NOT_STARTED</p>"));}
@Test void anonymousOrdersDenied()throws Exception{mvc.perform(get("/api/mobile/v1/orders")).andExpect(status().isUnauthorized());}
@Test void employeeOrdersDenied()throws Exception{mvc.perform(get("/api/mobile/v1/orders").with(user("employee").roles("EMPLOYEE"))).andExpect(status().isForbidden());}
@Test void customerListsOnlyPrincipalOrders()throws Exception{mvc.perform(get("/api/mobile/v1/orders").with(authentication(new CustomerAuthentication(7L)))).andExpect(status().isOk()).andExpect(jsonPath("$.content[0].orderNumber").value("TSS-1"));verify(service).list(eq(7L),eq(0),eq(10),any(),any(),any(),any(),any(),eq("newest"));}
@Test void detailIsCustomerSafe()throws Exception{mvc.perform(get("/api/mobile/v1/orders/TSS-1").with(authentication(new CustomerAuthentication(7L)))).andExpect(status().isOk()).andExpect(jsonPath("$.paymentStatus").value("NOT_STARTED")).andExpect(jsonPath("$.buyingPrice").doesNotExist()).andExpect(jsonPath("$.warehouseId").doesNotExist()).andExpect(jsonPath("$.idempotencyKey").doesNotExist());}
@Test void timelineIsAvailable()throws Exception{mvc.perform(get("/api/mobile/v1/orders/TSS-1/timeline").with(authentication(new CustomerAuthentication(7L)))).andExpect(status().isOk()).andExpect(jsonPath("$[0].status").value("PENDING_CONFIRMATION"));}
@Test void cancellationDoesNotAcceptStatusOrCustomerId()throws Exception{mvc.perform(post("/api/mobile/v1/orders/TSS-1/cancellation-requests").with(authentication(new CustomerAuthentication(7L))).contentType("application/json").content("{\"reasonCode\":\"ORDERED_BY_MISTAKE\",\"idempotencyKey\":\"k\",\"orderStatus\":\"CANCELLED\",\"customerId\":999}")).andExpect(status().isCreated()).andExpect(jsonPath("$.status").value("REQUESTED"));verify(service).cancel(eq(7L),eq("TSS-1"),any());}
@Test void returnFoundationStartsRequested()throws Exception{mvc.perform(post("/api/mobile/v1/orders/TSS-1/return-requests").with(authentication(new CustomerAuthentication(7L))).contentType("application/json").content("{\"idempotencyKey\":\"r\",\"preferredResolution\":\"REFUND_REQUESTED\",\"items\":[{\"orderItemId\":1,\"quantity\":1,\"reasonCode\":\"DAMAGED_OR_DEFECTIVE\"}]}")).andExpect(status().isCreated()).andExpect(jsonPath("$.status").value("REQUESTED"));}
@Test void documentTruthfulUnpaidAndSafe()throws Exception{mvc.perform(get("/api/mobile/v1/orders/TSS-1/document").with(authentication(new CustomerAuthentication(7L)))).andExpect(status().isOk()).andExpect(jsonPath("$.fileName").value("TSS-1-order-summary.html")).andExpect(jsonPath("$.html").value(org.hamcrest.Matchers.containsString("NOT_STARTED"))).andExpect(jsonPath("$.html").value(org.hamcrest.Matchers.not(org.hamcrest.Matchers.containsString("PAID"))));}}

